sys_script_include.script:
var caseItsmUtil = Class.create();
caseItsmUtil.prototype = {
    initialize: function() {},

    // Create Incident from Case
    createIncidentFromCase: function(caseGr) {
        var inc = new GlideRecord('incident');
        inc.initialize();
        inc.short_description = caseGr.short_description;
        inc.priority = caseGr.priority;
        inc.category = caseGr.category;
		inc.caller_id = caseGr.opened_by;
        var incSysId = inc.insert();

        caseGr.u_incident = incSysId;
        caseGr.update();

        return incSysId;
    },

    // Create Problem from Case
    createProblemFromCase: function(caseGr) {
        var prb = new GlideRecord('problem');
        prb.initialize();
        prb.short_description = caseGr.short_description;
        prb.priority = caseGr.priority;
        prb.category = caseGr.category;
        var prbSysId = prb.insert();

        caseGr.problem = prbSysId;
        caseGr.update();

        return prbSysId;
    },

    // Create Change from Case
    createChangeFromCase: function(caseGr) {
        var chg = new GlideRecord('change_request');
        chg.initialize();
        chg.short_description = caseGr.short_description;
        chg.priority = caseGr.priority;
        chg.category = caseGr.category;
		chg.requested_by = caseGr.opened_by;
        //chg.type = "standard"; // adjust if needed
        var chgSysId = chg.insert();

        caseGr.change = chgSysId;
        caseGr.update();

        return chgSysId;
    },

    type: 'caseItsmUtil'
};

sys_script.script:
(function executeRule(current, previous /*null when async*/) {

	// Add your code here
var utils = new caseItsmUtil();
    utils.createChangeFromCase(current);
})(current, previous);
